index 2d7524e8018b..9a80bbbe2fd4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1103,6 +1103,48 @@ static Value *foldPowerOf2AndShiftedMask(ICmpInst *Cmp0, ICmpInst *Cmp1,
   }
   return nullptr;
 }
+/// Try to fold (icmp ult X, C1) & (icmp eq (and X, Mask), C2) into (icmp eq (and X, Mask), C2)
+/// when the masked equality implies the range check.
+/// The condition is: for (X & Mask) == C2 to be true, X is in range [C2, C2 | ~Mask].
+/// If C2 | ~Mask < C1, then the range check is redundant.
+static Value *foldICmpUltWithICmpEqAnd(ICmpInst *Cmp0, ICmpInst *Cmp1, bool IsAnd,
+                                       InstCombiner::BuilderTy &Builder) {
+  if (!IsAnd)
+    return nullptr;
+
+  // Match: (icmp ult X, C1) and (icmp eq (and X, Mask), C2)
+  Value *X0;
+  const APInt *C1;
+  if (!match(Cmp0, m_SpecificICmp(ICmpInst::ICMP_ULT, m_Value(X0), m_APInt(C1))))
+    return nullptr;
+
+  Value *AndOp;
+  const APInt *C2, *Mask;
+  if (!match(Cmp1, m_SpecificICmp(ICmpInst::ICMP_EQ,
+                          m_And(m_Value(AndOp), m_APInt(Mask)),
+                          m_APInt(C2))))
+    return nullptr;
+
+  // The and operand must be the same as the range check operand
+  if (AndOp != X0)
+    return nullptr;
+
+  // Compute the maximum value X can have: C2 | ~Mask
+  APInt MaxVal = *C2 | ~*Mask;
+
+  // Check if the max value is less than C1 (the range check bound)
+  if (!MaxVal.ult(*C1))
+    return nullptr;
+
+  // Require that the range check has only one use (this and instruction)
+  // so we can safely remove it
+  if (!Cmp0->hasOneUse())
+    return nullptr;
+
+  // The masked equality implies the range check, so we can simplify to just
+  // the masked equality
+  return Cmp1;
+}

 /// Commuted variants are assumed to be handled by calling this function again
 /// with the parameters swapped.
@@ -2730,6 +2772,18 @@ Instruction *InstCombinerImpl::visitAnd(BinaryOperator &I) {
               foldAndOrOfSelectUsingImpliedCond(Op0, *SI1, /* IsAnd */ true))
         return R;
     }
+    // Try folding (icmp ult X, C1) & (icmp eq (and X, Mask), C2) when the masked
+    // equality implies the range check.
+    if (auto *ICmp0 = dyn_cast<ICmpInst>(Op0)) {
+      if (auto *ICmp1 = dyn_cast<ICmpInst>(Op1)) {
+        if (Value *V = foldICmpUltWithICmpEqAnd(ICmp0, ICmp1, /*IsAnd=*/true,
+                                                Builder))
+          return replaceInstUsesWith(I, V);
+        if (Value *V = foldICmpUltWithICmpEqAnd(ICmp1, ICmp0, /*IsAnd=*/true,
+                                                Builder))
+          return replaceInstUsesWith(I, V);
+      }
+    }
   }

   if (Instruction *FoldedLogic = foldBinOpIntoSelectOrPhi(I))

